export interface VideoGetByIDInput {
  id: number;
}

/**
 * ListInput carries the pagination + filter + sort dimensions for
 * video.list. Sort/Order are whitelisted at the validator; the SQL
 * defaults to start_download_at DESC when either is empty.
 */
export interface VideoListInput {
  limit: number;
  offset: number;
  status?: string;
  sort?: string;
  order?: string;
}

export interface VideoListPageCursor {
  sort_number?: number;
  sort_int?: string;
  sort_text?: string;
  sort_time?: string;
  start_download_at: string;
  id: number;
}

export interface VideoListPageInput {
  limit: number;
  status?: string;
  sort?: string;
  order?: string;
  quality?: string;
  broadcaster_id?: string;
  language?: string;
  duration?: string;
  size?: string;
  window?: string;
  incomplete_only?: boolean;
  /**
   * TerminalOnly keeps active in-flight rows out of history-style views while
   * still allowing those views to include both active terminal rows and
   * tombstones through Scope="all".
   */
  terminal_only?: boolean;
  /**
   * Scope selects the tombstone state. Empty/"active" keeps the library
   * default (live recordings only); "removed" and "all" power the
   * removed-inclusive history surface. Channel/category grids and search
   * never expose this and stay active-only.
   */
  scope?: string;
  cursor?: VideoListPageCursor;
  direction?: string;
}

export interface VideoListPageResponse {
  items: VideoResponse[];
  next_cursor?: VideoListPageCursor;
}

export interface VideoOK {
  ok: boolean;
}

/**
 * VideoPageCursor identifies the last row from the previous page so the
 * next query can continue with stable keyset pagination.
 */
export interface VideoPageCursor {
  start_download_at: string;
  id: number;
}

/**
 * VideoPageResponse is the cursor-paginated envelope for channel/category
 * detail video grids. next_cursor is omitted on the terminal page.
 */
export interface VideoPageResponse {
  items: VideoResponse[];
  next_cursor?: VideoPageCursor;
}

/** VideoPartResponse mirrors repository.VideoPart with stable JSON tags. */
export interface VideoPartResponse {
  id: number;
  part_index: number;
  filename: string;
  quality: string;
  fps?: number;
  codec: string;
  segment_format: string;
  duration_seconds: number;
  size_bytes: number;
  thumbnail?: string;
  start_media_seq: number;
  end_media_seq?: number;
}

export interface VideoPlaybackAssetResponse {
  status: PlaybackAssetStatus;
  filename?: string;
  mime_type?: string;
  duration_seconds?: number;
  size_bytes?: number;
  error?: string;
  generated_at?: string;
  last_accessed_at?: string;
  updated_at: string;
}

/**
 * VideoResponse is the wire shape for a video record. broadcaster_*
 * and profile_image_url come from a JOIN-equivalent channel lookup
 * that the service layer does in bulk once per response — the frontend
 * renders the video card's avatar + channel link without a per-row
 * channel.getById, which would trip trpcgo's batching ceiling on a
 * full grid.
 */
export interface VideoResponse {
  id: number;
  job_id: string;
  filename: string;
  display_name: string;
  /**
   * Title is the stream title at download-start time. Empty when
   * Twitch didn't surface a title (manual trigger on an offline
   * channel); the UI falls back to display_name in that case.
   */
  title: string;
  status: VideoStatus;
  /**
   * CompletionKind distinguishes clean-end from partial/cancelled
   * recordings. See repository.CompletionKind* constants. The UI
   * renders a secondary badge (PARTIAL) for DONE+partial and
   * replaces the FAILED badge with CANCELLED when the operator
   * explicitly cancelled.
   */
  completion_kind: CompletionKind;
  /**
   * Truncated is true when the recording stopped before the
   * broadcast ended — operator cancel, mid-run failure, or a clean
   * finalize that never observed EXT-X-ENDLIST. Orthogonal to
   * CompletionKind. The dashboard's videos page uses this to
   * distinguish "we have the whole stream" from "we only have the
   * part of the broadcast we recorded for."
   */
  truncated: boolean;
  /**
   * Quality is the display label for the selected recorded rendition
   * when Stage 3 has picked one (e.g. 1080p60). Before that it falls
   * back to the requested quality enum (HIGH/MEDIUM/LOW).
   */
  quality: string;
  fps?: number;
  /**
   * IsAudioOnly is the server-owned playback classification. Clients use this
   * instead of re-deriving audio-ness from file extensions, MIME types, or
   * playback artifact metadata that can disagree during migrations/backfills.
   */
  is_audio_only: boolean;
  broadcaster_id: string;
  /**
   * BroadcasterLogin / BroadcasterName / ProfileImageURL come from
   * the channels mirror. When the broadcaster isn't locally synced
   * (rare but possible for historical videos) these are empty and
   * the frontend falls back to DisplayName + initials avatar.
   */
  broadcaster_login?: string;
  broadcaster_name?: string;
  profile_image_url?: string;
  primary_category_id?: string;
  primary_category_name?: string;
  primary_category_box_art_url?: string;
  stream_id?: string;
  viewer_count: number;
  language: string;
  duration_seconds?: number;
  size_bytes?: number;
  thumbnail?: string;
  error?: string;
  start_download_at: string;
  downloaded_at?: string;
  /**
   * DeletedAt is set on tombstoned (removed) recordings; DeletionKind
   * records why ("retention" | "manual"). Both nil for live recordings.
   * Surfaced only on the removed-inclusive history surface (listPage with
   * scope removed/all); the library default scope never returns these rows.
   */
  deleted_at?: string;
  deletion_kind?: string;
  /**
   * DeleteRequestedAt is set while a manual removal is queued but not yet
   * finalized by the background deletion task.
   */
  delete_requested_at?: string;
  /**
   * Parts is populated only by GetByID — list endpoints skip it
   * to avoid N+1 queries on grid views.
   */
  parts?: VideoPartResponse[];
  /**
   * PlaybackArtifact is populated only by GetByID. Ready means the watch page
   * can use /api/v1/videos/{id}/playback/stream; building/failed/unavailable
   * keep the client-side part sequencer as the fallback.
   */
  playback_artifact?: VideoPlaybackAssetResponse;
}

/**
 * SearchInput drives video.search for the global navbar search. Query is
 * capped to bound LIKE/ILIKE work across titles, broadcasters, and categories.
 */
export interface VideoSearchInput {
  query: string;
  limit?: number;
}

export type VideoStatus = "PENDING" | "RUNNING" | "DONE" | "FAILED";

/** VideoSummary is a trimmed video view for the request list. */
export interface VideoSummary {
  id: number;
  filename: string;
  display_name: string;
  status: string;
}

export interface VideorequestListInput {
  limit: number;
  offset: number;
}

export interface VideorequestOK {
  ok: boolean;
}

export interface WhitelistEntryInfo {
  twitch_user_id: string;
  added_at: string;
}

export interface WhitelistIDInput {
  twitch_user_id: string;
}

type $Query<TInput, TOutput> = TRPCQueryProcedure<{ input: TInput; output: TOutput; meta: object }>;
type $Mutation<TInput, TOutput> = TRPCMutationProcedure<{ input: TInput; output: TOutput; meta: object }>;
type $Subscription<TInput, TOutput> = TRPCSubscriptionProcedure<{ input: TInput; output: TOutput; meta: object }>;

type AppRouterRecord = {
  auth: {
    logout: $Mutation<void, LogoutResult>;
    revokeSession: $Mutation<RevokeSessionInput, LogoutResult>;
    session: $Query<void, SessionResponse>;
    sessions: $Query<void, SessionInfo[]>;
  };
  category: {
    getById: $Query<CategoryGetByIDInput, CategoryResponse>;
    list: $Query<void, CategoryResponse[]>;
    listPage: $Query<CategoryListPageInput, CategoryPageResponse>;
    listWithVideos: $Query<void, CategoryResponse[]>;
    search: $Query<CategorySearchInput, CategoryResponse[]>;
    searchWithVideos: $Query<CategorySearchInput, CategoryResponse[]>;
  };
  channel: {
    getById: $Query<ChannelGetByIDInput, ChannelResponse>;
    getByLogin: $Query<GetByLoginInput, ChannelResponse>;
    latestLive: $Query<LatestLiveInput, LatestLiveResponse[]>;
    list: $Query<void, ChannelResponse[]>;
    listFollowed: $Query<void, ChannelResponse[]>;
    listPage: $Query<ChannelListPageInput, ChannelPageResponse>;
    search: $Query<ChannelSearchInput, ChannelResponse[]>;
    syncFromTwitch: $Mutation<SyncFromTwitchInput, ChannelResponse>;
  };
  eventsub: {
    config: $Query<void, ConfigResponse>;
    latestSnapshot: $Query<void, LatestSnapshotResponse>;
    listSnapshots: $Query<EventsubListInput, ListSnapshotsResponse>;
    listSubscriptions: $Query<EventsubListInput, ListSubscriptionsResponse>;
    snapshot: $Mutation<void, SnapshotResponse>;
    subscribeStreamOnline: $Mutation<SubscribeInput, SubscriptionResponse>;
    unsubscribe: $Mutation<UnsubscribeInput, UnsubscribeResponse>;
    updateConfig: $Mutation<UpdateConfigInput, ConfigResponse>;
  };
  recordingWebhook: {
    config: $Query<void, RecordingWebhookConfigResponse>;
    deliveries: $Query<void, RecordingWebhookDeliveryResponse[]>;
    regenerateSecret: $Mutation<void, RecordingWebhookConfigResponse>;
    retryDelivery: $Mutation<RecordingWebhookRetryDeliveryInput, RecordingWebhookDeliveryResponse>;
    testDelivery: $Mutation<void, RecordingWebhookTestResult>;
    updateConfig: $Mutation<RecordingWebhookUpdateConfigInput, RecordingWebhookConfigResponse>;
  };
  schedule: {
    create: $Mutation<CreateInput, ScheduleResponse>;
    delete: $Mutation<ScheduleDeleteInput, DeleteResponse>;
    getById: $Query<ScheduleGetByIDInput, ScheduleResponse>;
    list: $Query<ScheduleListInput, ScheduleListResponse>;
    mine: $Query<ScheduleListInput, ScheduleListResponse>;
    pauseState: $Query<void, PauseStateResponse>;
    setPaused: $Mutation<SetPausedInput, PauseStateResponse>;
    toggle: $Mutation<ScheduleToggleInput, ScheduleResponse>;
    update: $Mutation<ScheduleUpdateInput, ScheduleResponse>;
  };
  settings: {
    get: $Query<void, SettingsResponse>;
    update: $Mutation<SettingsUpdateInput, SettingsResponse>;
  };
  stream: {
    active: $Query<void, StreamResponse[]>;
    byBroadcaster: $Query<StreamByBroadcasterInput, StreamResponse[]>;
    followed: $Query<void, FollowedStreamResponse[]>;
    lastLive: $Query<LastLiveInput, StreamResponse>;
    live: $Subscription<void, StreamLiveEvent>;
    liveIds: $Query<void, string[]>;
    status: $Subscription<void, StreamStatusEvent>;
  };
  system: {
    addWhitelist: $Mutation<WhitelistIDInput, SystemOK>;
    eventLogs: $Query<EventLogsInput, EventLogsResponse>;
    events: $Subscription<void, EventLogEvent>;
    fetchLogs: $Query<FetchLogsInput, FetchLogsResponse>;
    listUsers: $Query<void, UserInfo[]>;
    listWhitelist: $Query<void, WhitelistEntryInfo[]>;
    playbackCacheConfig: $Query<void, PlaybackCacheConfigResponse>;
    removeWhitelist: $Mutation<WhitelistIDInput, SystemOK>;
    searchEventLogs: $Query<SearchEventLogsInput, SearchEventLogsResponse>;
    updatePlaybackCacheConfig: $Mutation<UpdatePlaybackCacheConfigInput, PlaybackCacheConfigResponse>;
    updateUserRole: $Mutation<UpdateUserRoleInput, UserInfo>;
  };
  tag: {
    list: $Query<void, TagResponse[]>;
  };
  task: {
    list: $Query<void, TaskListResponse>;
    runNow: $Mutation<RunNowInput, TaskResponse>;
    status: $Subscription<void, TaskStatusEvent>;
    toggle: $Mutation<TaskToggleInput, TaskResponse>;
  };
  video: {
    activeDownloads: $Query<void, ActiveDownloadResponse[]>;
    activeDownloadsLive: $Subscription<void, ActiveDownloadResponse[]>;
    byBroadcaster: $Query<VideoByBroadcasterInput, VideoPageResponse>;
    byCategory: $Query<ByCategoryInput, VideoPageResponse>;
    cancel: $Mutation<CancelInput, VideoOK>;
    categories: $Query<CategoriesInput, VideoCategory[]>;
    delete: $Mutation<VideoDeleteInput, VideoOK>;
    downloadCapacity: $Query<void, DownloadCapacityResponse>;
    downloadProgress: $Subscription<DownloadProgressInput, ProgressEvent>;
    getById: $Query<VideoGetByIDInput, VideoResponse>;
    list: $Query<VideoListInput, VideoResponse[]>;
    listPage: $Query<VideoListPageInput, VideoListPageResponse>;
    search: $Query<VideoSearchInput, VideoResponse[]>;
    snapshots: $Query<SnapshotsInput, string[]>;
    statistics: $Query<void, StatisticsResponse>;
    statisticsByBroadcaster: $Query<ChannelStatisticsInput, ChannelStatisticsResponse>;
    timeline: $Query<TimelineInput, TimelineEvent[]>;
    titles: $Query<TitlesInput, TitleItem[]>;
    triggerDownload: $Mutation<TriggerDownloadInput, TriggerDownloadResponse>;
  };
  videorequest: {
    mine: $Query<VideorequestListInput, VideoSummary[]>;
    request: $Mutation<RequestInput, VideorequestOK>;
  };
};

type $ErrorShape = { code: number; message: string; data: { code: string; httpStatus: number; path?: string } };
type $RootTypes = { ctx: object; meta: object; errorShape: $ErrorShape; transformer: false };

export type AppRouter = {
  _def: TRPCRouterDef<$RootTypes, AppRouterRecord>;
  createCaller: TRPCRouterCaller<$RootTypes, AppRouterRecord>;
};

export type RouterInputs = inferRouterInputs<AppRouter>;

export type RouterOutputs = inferRouterOutputs<AppRouter>;
